import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Loader2, Store } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";

interface CreateStoreDialogProps {
  trigger: React.ReactNode;
}

const CreateStoreDialog = ({ trigger }: CreateStoreDialogProps) => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    type: "",
    address: "",
    phone: "",
  });

  const handleSubmit = async () => {
    if (!user || !formData.name.trim()) return;
    setLoading(true);

    try {
      const { data, error } = await supabase.functions.invoke("create-merchant-store", {
        body: {
          name: formData.name.trim(),
          type: formData.type ? formData.type.split(",").map(s => s.trim()).filter(Boolean) : [],
          address: formData.address.trim() || null,
          phone: formData.phone.trim() || null,
        },
      });

      if (error) throw error;
      if (data?.error) throw new Error(data.error);

      toast({
        title: t("merchant.storeCreated", "商店创建成功"),
        description: t("merchant.storeCreatedDesc", "您的商店已创建，可以开始管理了"),
      });

      queryClient.invalidateQueries({ queryKey: ["merchant-restaurants"] });
      setOpen(false);
      setFormData({ name: "", type: "", address: "", phone: "" });
    } catch (e: any) {
      console.error("Failed to create store:", e);
      toast({
        title: t("common.error", "错误"),
        description: e.message || t("merchant.storeCreateFailed", "创建失败，请重试"),
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>{trigger}</DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Store className="h-5 w-5 text-primary" />
            {t("merchant.createStore", "创建商店")}
          </DialogTitle>
          <DialogDescription>
            {t("merchant.createStoreDesc", "填写基本信息来创建您的商店")}
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4 py-2">
          <div className="space-y-2">
            <Label>{t("merchant.storeName", "商店名称")} *</Label>
            <Input
              value={formData.name}
              onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
              placeholder={t("merchant.storeNamePlaceholder", "请输入商店名称")}
            />
          </div>

          <div className="space-y-2">
            <Label>{t("merchant.storeType", "商店类型")}</Label>
            <Input
              value={formData.type}
              onChange={(e) => setFormData(prev => ({ ...prev, type: e.target.value }))}
              placeholder={t("merchant.storeTypePlaceholder", "例如: 中餐, 日料 (逗号分隔)")}
            />
          </div>

          <div className="space-y-2">
            <Label>{t("merchant.storeAddress", "地址")}</Label>
            <Input
              value={formData.address}
              onChange={(e) => setFormData(prev => ({ ...prev, address: e.target.value }))}
              placeholder={t("merchant.storeAddressPlaceholder", "请输入商店地址")}
            />
          </div>

          <div className="space-y-2">
            <Label>{t("merchant.storePhone", "电话")}</Label>
            <Input
              value={formData.phone}
              onChange={(e) => setFormData(prev => ({ ...prev, phone: e.target.value }))}
              placeholder={t("merchant.storePhonePlaceholder", "请输入联系电话")}
            />
          </div>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => setOpen(false)}>
            {t("common.cancel", "取消")}
          </Button>
          <Button onClick={handleSubmit} disabled={loading || !formData.name.trim()}>
            {loading && <Loader2 className="h-4 w-4 mr-1 animate-spin" />}
            {t("merchant.createStore", "创建商店")}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

export default CreateStoreDialog;
